data.output:
					Kind:    IssueCascadeUnknown,
					ID:      to,
					Message: fmt.Sprintf("cascade rule refers to unknown target doc %q", to),
				})
				continue
			}
			if !containsString(child.DependsOn, from) {
				child.DependsOn = append(child.DependsOn, from)
			}
		}
	}

	for id := range g.Documents {
		g.Documents[id].DependsOn = dedupeSortedStrings(g.Documents[id].DependsOn)
	}
	g.buildDependents()
	// Re-run integrity scans that can change after id_to_path/cascade apply.
	g.rescanAfterConfig()
	g.detectCycles()
	g.finalizeWarnings()
}

// rescanAfterConfig refreshes integrity detections that depend on the final
// document set. Currently this just re-runs missing-dep detection so deps
// pulled in by cascade rules or id_to_path entries are evaluated, and dedupes
// any duplicate issues introduced by the rescan.
func (g *Graph) rescanAfterConfig() {
	// Wipe prior missing_dep entries because applyConfig may have resolved
	// some of them by promoting id_to_path targets into Documents.
	filtered := g.Issues[:0]
	for _, issue := range g.Issues {
		if issue.Kind == IssueMissingDep {
			continue
		}
		filtered = append(filtered, issue)
	}
	g.Issues = filtered
	g.detectMissingDeps()
}

func findMarkdownFiles(root string, roots []string) ([]string, error) {
	targetDirs := []string{root}
	if len(roots) > 0 {
		targetDirs = roots
	}

	rootClean := filepath.Clean(root)
	files := []string{}
	for _, base := range targetDirs {
		cleanRoot := filepath.Clean(base)
		err := filepath.Walk(cleanRoot, func(path string, info os.FileInfo, err error) error {
			if err != nil {
				return nil
			}
			if info == nil {
				return nil
			}
			// Exclude any repository-relative path that contains a hidden
			// segment. This catches configured roots that start inside
			// `.agents/`, `.claude/`, `.ddx/`, `.skills/`, or any future
			// dot-prefixed tool tree before either directory or file
			// acceptance can happen.
			if hasHiddenPathSegment(relPath(rootClean, path)) {
				if info.IsDir() {
					return filepath.SkipDir
				}
				return nil
			}
			if info.IsDir() {
				name := filepath.Base(path)
				// Skip tool-managed directories. .claude and .agents are
				// agent-skill workspaces that often contain stale copies of
				// canonical docs; a worktrees/ directory at any depth is
				// agent-scratch and must not be surfaced as canonical documents.
				switch name {
				case ".git", ".ddx", ".claude", ".agents", "worktrees":
					return filepath.SkipDir
				}
				return nil
			}
			ext := strings.ToLower(filepath.Ext(path))
			if ext != ".md" {
				return nil
			}
			files = append(files, path)
			return nil
		})
		if err != nil {
			return nil, err
		}
	}
	sort.Strings(files)
	return files, nil
}

// hasHiddenPathSegment reports whether the provided repository-relative path
// contains any dot-prefixed segment. It is used to exclude hidden/tool-managed
// trees even when a configured graph root starts inside that subtree.
func hasHiddenPathSegment(path string) bool {
	slash := filepath.ToSlash(path)
	if slash == "" || slash == "." {
		return false
	}
	for _, segment := range strings.Split(slash, "/") {
		if segment == "" || segment == "." || segment == ".." {
			continue
		}
		if strings.HasPrefix(segment, ".") {
			return true
		}
	}
	return false
}

// relPath returns filePath expressed relative to root. If filePath cannot be
// made relative (e.g. different volumes on Windows) the cleaned absolute path
// is returned. Callers treat the result as the canonical document path.
func relPath(root, filePath string) string {
	clean := filepath.Clean(filePath)
	if rel, err := filepath.Rel(root, clean); err == nil && !strings.HasPrefix(rel, ".."+string(filepath.Separator)) && rel != ".." {
		return rel
	}
	return clean
}

// absPath returns an absolute path for a document path stored on a Graph.
// Document paths are relative to g.RootDir; callers that need to touch the
// file on disk (read/write/git) must join with the root first.
func (g *Graph) absPath(docPath string) string {
	if filepath.IsAbs(docPath) {
		return docPath
	}
	return filepath.Join(g.RootDir, docPath)
}

func ParseDocument(path string) (*Document, error) {
	content, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	frontmatter, body, err := ParseFrontmatter(content)
	if err != nil {
		return nil, err
	}
	if !frontmatter.HasFrontmatter || frontmatter.Doc.ID == "" {
		return nil, fmt.Errorf("%w in %s", ErrNotDocGraphDocument, path)
	}
	if observed := len([]byte(frontmatter.Doc.Prompt)); observed > docgraphPromptCapBytes {
		return nil, fmt.Errorf(
			"%w: document %q at %s prompt metadata is %d bytes, cap %d bytes (configurable via .ddx/config.yaml:evidence_caps.max_prompt_bytes)",
			ErrPromptMetadataOversize, frontmatter.Doc.ID, path, observed, docgraphPromptCapBytes)
	}

	review := ReviewMetadata{
		SelfHash:   frontmatter.Doc.Review.SelfHash,
		ReviewedAt: frontmatter.Doc.Review.ReviewedAt,
		Deps:       frontmatter.Doc.Review.Deps,
	}
	if review.Deps == nil {
		review.Deps = map[string]string{}
	}

	doc := &Document{
		ID:            frontmatter.Doc.ID,
		Title:         extractTitle([]byte(body)),
		DependsOn:     dedupeSortedStrings(frontmatter.Doc.DependsOn),
		Inputs:        dedupeSortedStrings(frontmatter.Doc.Inputs),
		Review:        review,
		ParkingLot:    frontmatter.Doc.ParkingLot,
		Prompt:        frontmatter.Doc.Prompt,
		ExecDef:       frontmatter.Doc.Exec,
		body:          body,
		bodyLinkTexts: extractBodyLinks(body),
	}
	if frontmatter.Raw != nil {
		doc.frontmatter = frontmatter.Raw
	}

	contentHash, err := HashDocument(frontmatter.Raw, body)
	if err != nil {
		return nil, err
	}
	doc.contentHash = contentHash
	return doc, nil
}

// ContentHash returns the deterministic content hash captured for this
// document at graph-build time. Callers comparing to a freshly-rebuilt graph
// can use this to detect whether the on-disk file has changed since the graph
// was last computed.
func (d *Document) ContentHash() string { return d.contentHash }

// HashDocumentFile parses the markdown file at path and returns the
// deterministic document content hash, or an error if the file is not a doc
// graph document. The hash matches Document.ContentHash() for the same file.
func HashDocumentFile(path string) (string, error) {
	doc, err := ParseDocument(path)
	if err != nil {
		return "", err
	}

	root := setupTestRepo(t, map[string]string{
		"docs/foo.md":                           "---\nddx:\n  id: foo\n---\n# Canonical Foo\n",
		".claude/worktrees/agent-x/docs/foo.md": "---\nddx:\n  id: foo.dup\n---\n# Shadow Foo\n",
		".claude/worktrees/agent-x/README.md":   "---\nddx:\n  id: shadow.readme\n---\n# Shadow Readme\n",
		"scratch/worktrees/agent-y/docs/bar.md": "---\nddx:\n  id: shadow.worktrees\n---\n# Shadow Worktree\n",
	})

	graph, err := BuildGraph(root)
	if err != nil {
		t.Fatal(err)
	}

	if graph.Documents["foo"] == nil {
		t.Fatal("expected canonical docs/foo.md document in graph")
	}
	if graph.Documents["foo.dup"] != nil {
		t.Error(".claude/worktrees shadow copy should be excluded")
	}
	if graph.Documents["shadow.readme"] != nil {
		t.Error(".claude/worktrees README.md should be excluded")
	}
	if graph.Documents["shadow.worktrees"] != nil {
		t.Error("worktrees/ subtree should be excluded regardless of parent")
	}

	for id, doc := range graph.Documents {
		if filepath.IsAbs(doc.Path) {
			t.Errorf("document %q has absolute path %q, want path relative to working dir", id, doc.Path)
		}
		if strings.Contains(filepath.ToSlash(doc.Path), ".claude/") {
			t.Errorf("document %q path %q contains .claude/ (worktrees must be skipped)", id, doc.Path)
		}
	}
	for key := range graph.PathToID {
		if filepath.IsAbs(key) {
			t.Errorf("PathToID key %q is absolute, want relative", key)
		}
		if strings.Contains(filepath.ToSlash(key), ".claude/") {
			t.Errorf("PathToID key %q contains .claude/", key)
		}
	}

	if doc := graph.Documents["foo"]; doc != nil {
		want := filepath.FromSlash("docs/foo.md")
		if doc.Path != want {
			t.Errorf("got doc.Path %q, want %q", doc.Path, want)
		}
	}
}

// TestBuildGraph_ExcludesDDxPluginsTree pins down the skip-list for
// `.ddx/plugins/`. Plugin trees check in their own copies of canonical
// docs (e.g. `.ddx/plugins/helix/docs/...`); those copies must never be
// merged into the project's documents graph because they would collide
// with the canonical `docs/` entries and produce duplicate_id issues.
//
// The basename skip on `.ddx` already handles a default top-level walk.
// This test additionally exercises the path-based defense for the case
// where a graph config configures a root that points directly inside
// `.ddx/`, bypassing the basename rule.
func TestBuildGraph_ExcludesDDxPluginsTree(t *testing.T) {
	root := setupTestRepo(t, map[string]string{
		"docs/feat.md":                              "---\nddx:\n  id: FEAT-001\n---\n# Canonical\n",
		".ddx/plugins/helix/docs/feat.md":           "---\nddx:\n  id: FEAT-001\n---\n# Plugin Shadow\n",
		".ddx/plugins/helix/docs/orphan.md":         "---\nddx:\n  id: plugin.orphan\n---\n# Plugin Orphan\n",
		".ddx/plugins/ddx/templates/library/lib.md": "---\nddx:\n  id: plugin.lib\n---\n# Plugin Lib\n",
	})

	// Default walk: basename rule on `.ddx` excludes the whole subtree.
	graph, err := BuildGraph(root)
	if err != nil {
		t.Fatal(err)
	}
	if graph.Documents["FEAT-001"] == nil {
		t.Fatal("expected canonical FEAT-001 in graph")
	}
	if graph.Documents["plugin.orphan"] != nil {
		t.Error("plugin doc plugin.orphan must be excluded by .ddx skip")
	}
	if graph.Documents["plugin.lib"] != nil {
		t.Error("plugin doc plugin.lib must be excluded by .ddx skip")
	}
	for _, issue := range filterIssuesByKind(graph.Issues, IssueDuplicateID) {
		t.Errorf("unexpected duplicate_id issue: %+v", issue)
	}

	// Direct walk into `.ddx/plugins/...`: simulates a graph config that
	// pointed roots at the plugin tree. The path-based defense must still
	// skip the contents.
	pluginRoot := filepath.Join(root, ".ddx", "plugins", "helix", "docs")
	files, err := findMarkdownFiles(root, []string{pluginRoot})
	if err != nil {
		t.Fatal(err)
	}
	if len(files) != 0 {
		t.Errorf("expected zero files under .ddx/plugins/ root, got %v", files)
	}
}

