// detectMissingDeps emits missing_dep issues for every declared dependency
// that does not resolve to a document in the graph. Runs after body-link
// resolution so link targets are already promoted to DependsOn.
func (g *Graph) detectMissingDeps() {
	for _, id := range sortedDocIDs(g.Documents) {
		doc := g.Documents[id]
		if doc == nil {
			continue
		}
		for _, dep := range doc.DependsOn {
			if _, ok := g.Documents[dep]; ok {
				continue
			}
			g.Issues = append(g.Issues, GraphIssue{
				Kind:    IssueMissingDep,
				Path:    doc.Path,
				ID:      dep,
				Message: fmt.Sprintf("document %q declares dependency %q which is not in the graph", doc.ID, dep),
			})
		}
	}
}

// sortedDocIDs returns the IDs of docs sorted for stable issue ordering.
func sortedDocIDs(docs map[string]*Document) []string {
	ids := make([]string, 0, len(docs))
	for id := range docs {
		ids = append(ids, id)
	}
	sort.Strings(ids)
	return ids
}

// finalizeWarnings rebuilds the deprecated Warnings string slice from Issues
// and sorts Issues deterministically so downstream callers see stable output.
func (g *Graph) finalizeWarnings() {
	sort.SliceStable(g.Issues, func(i, j int) bool {
		if g.Issues[i].Kind != g.Issues[j].Kind {
			return g.Issues[i].Kind < g.Issues[j].Kind
		}
		return g.Issues[i].Message < g.Issues[j].Message
	})
	g.Warnings = MessageLines(g.Issues)
	if g.Warnings == nil {
		g.Warnings = []string{}
	}
	if len(g.ValidationWarnings) > 1 {
		sort.Strings(g.ValidationWarnings)
	}
}

// validateMetricReferences resolves metric-linked execution definitions and
// records fatal errors for dangling metric_id values plus warnings when the
// linked metric artifact's documentary budget disagrees with the gate ratchet.
func (g *Graph) validateMetricReferences() {
	for _, id := range sortedDocIDs(g.Documents) {
		doc := g.Documents[id]
		if doc == nil || doc.ExecDef == nil || doc.ExecDef.Metric == nil {
			continue
		}
		metricID := strings.TrimSpace(doc.ExecDef.Metric.MetricID)
		if metricID == "" {
			continue
		}

		metricDoc, ok := g.Documents[metricID]
		if !ok || metricDoc == nil || !isMetricArtifact(metricDoc) {
			g.Issues = append(g.Issues, GraphIssue{
				Kind:    IssueMissingMetricArtifact,
				Path:    doc.Path,
				ID:      metricID,
				Message: fmt.Sprintf("document %q declares execution metric_id %q which does not resolve to a MET artifact", doc.ID, metricID),
			})
			continue
		}

		budget, budgetOK := metricBudget(metricDoc)
		if !budgetOK {
			continue
		}
		ratchet, ratchetOK := execRatchet(doc)
		if !ratchetOK {
			continue
		}
		if budget != ratchet {
			g.ValidationWarnings = append(g.ValidationWarnings,
				fmt.Sprintf("metric artifact %q budget %g conflicts with gate ratchet %g on %q; gate ratchet is authoritative", metricID, budget, ratchet, doc.ID))
		}
	}
}

func isMetricArtifact(doc *Document) bool {
	if doc == nil || !strings.HasPrefix(doc.ID, "MET-") || doc.frontmatter == nil {
		return false
	}
	return findMappingValue(doc.frontmatter, "metric") != nil
}

func metricBudget(doc *Document) (float64, bool) {
	if doc == nil || doc.frontmatter == nil {
		return 0, false
	}
	metricNode := findMappingValue(doc.frontmatter, "metric")
	if metricNode == nil {
		return 0, false
	}
	budgetNode := findMappingValue(metricNode, "budget")
	if budgetNode == nil {
		return 0, false
	}
	var budget float64
	if err := budgetNode.Decode(&budget); err != nil {
		return 0, false
	}
	return budget, true
}

func execRatchet(doc *Document) (float64, bool) {
	if doc == nil || doc.frontmatter == nil {
		return 0, false
	}
	ddxNode := findMappingValue(doc.frontmatter, "ddx")
	if ddxNode == nil {
		return 0, false
	}
	execNode := findMappingValue(ddxNode, "execution")
	if execNode == nil {
		return 0, false
	}
	threshNode := findMappingValue(execNode, "thresholds")
	if threshNode == nil {
		return 0, false
	}
	ratchetNode := findMappingValue(threshNode, "ratchet")
	if ratchetNode == nil {
		return 0, false
	}
	var ratchet float64
	if err := ratchetNode.Decode(&ratchet); err != nil {
		return 0, false
	}
	return ratchet, true
}

func (g *Graph) applyConfigDefaults() {
	for _, doc := range g.Documents {
		doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
		doc.Inputs = dedupeSortedStrings(doc.Inputs)
	}
}

func (g *Graph) applyConfig(configs []GraphConfig) {
	if len(configs) == 0 {
		return
	}

	idToPath := make(map[string]string)
	cascade := make(map[string][]string)
	for _, cfg := range configs {
		for id, rawPath := range cfg.IDToPath {
			if id == "" || rawPath == "" {
				continue
			}
			idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
		}
		for from, tos := range cfg.Cascade {
			for _, to := range tos {
				if from == "" || to == "" {
					continue
				}
				cascade[from] = append(cascade[from], to)
			}
		}
		if len(cfg.IDMap) > 0 {
			for id, rawPath := range cfg.IDMap {
				if id == "" || rawPath == "" {
					continue
				}
				idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
			}
		}
		if len(cfg.Required) > 0 {
			for _, id := range cfg.Required {
				if _, ok := g.Documents[id]; !ok {
					g.Issues = append(g.Issues, GraphIssue{
						Kind:    IssueRequiredRootMissing,
						ID:      id,
						Message: fmt.Sprintf("required root document %q not found", id),
					})
				}
			}
		}
	}

	if len(idToPath) > 0 {
		for id, path := range idToPath {
			if _, ok := g.Documents[id]; ok {
				continue
			}
			if _, err := os.Stat(path); err != nil {
				g.Issues = append(g.Issues, GraphIssue{
					Kind:    IssueIDPathMissing,
					ID:      id,
					Path:    relPath(g.RootDir, path),
					Message: fmt.Sprintf("id_to_path entry %q -> %q does not exist", id, path),
				})
				continue
			}
			doc, err := ParseDocument(path)
			if err != nil {
				if errors.Is(err, ErrNotDocGraphDocument) {
					g.Issues = append(g.Issues, GraphIssue{
						Kind:    IssueIDPathMissing,
						ID:      id,
						Path:    relPath(g.RootDir, path),
						Message: fmt.Sprintf("id_to_path entry %q -> %q is not a doc graph document", id, path),
					})
					continue
				}
				g.Issues = append(g.Issues, GraphIssue{
					Kind:    IssueIDPathMissing,
					ID:      id,
					Path:    relPath(g.RootDir, path),
					Message: fmt.Sprintf("id_to_path entry %q -> %q could not be loaded: %v", id, path, err),
				})
				continue
			}
			if doc.ID != id {
				g.Issues = append(g.Issues, GraphIssue{
					Kind:    IssueIDPathMismatch,
					ID:      id,
					Path:    relPath(g.RootDir, path),
					Message: fmt.Sprintf("id_to_path mismatch for %q: %q declares %q", id, path, doc.ID),
				})
				continue
			}
			g.Documents[id] = doc
			doc.Path = relPath(g.RootDir, path)
			g.PathToID[doc.Path] = id
		}
	}

	for from, toIDs := range cascade {
		if _, ok := g.Documents[from]; !ok {
			g.Issues = append(g.Issues, GraphIssue{
				Kind:    IssueCascadeUnknown,
				ID:      from,
				Message: fmt.Sprintf("cascade rule refers to unknown dependency root %q", from),
			})
			continue
		}
		for _, to := range dedupeSortedStrings(toIDs) {
			if to == "" {
				continue
			}
			child, ok := g.Documents[to]
			if !ok {
				g.Issues = append(g.Issues, GraphIssue{
					Kind:    IssueCascadeUnknown,
					ID:      to,
					Message: fmt.Sprintf("cascade rule refers to unknown target doc %q", to),
				})
				continue
			}
			if !containsString(child.DependsOn, from) {
				child.DependsOn = append(child.DependsOn, from)
			}
		}
	}

	for id := range g.Documents {
		g.Documents[id].DependsOn = dedupeSortedStrings(g.Documents[id].DependsOn)
	}
	g.buildDependents()
	// Re-run integrity scans that can change after id_to_path/cascade apply.
	g.rescanAfterConfig()
	g.detectCycles()
	g.finalizeWarnings()
}

